/**
 * Detalle — Bloque de Concorde (Voyager DS)
 *
 * Página de detalle. Por ahora es solo el lienzo base: un fondo blanco de
 * 799 × 1483. Iremos montando las secciones encima.
 */

import type { JSX } from "react";
import AuctionStatus from "../../../components/AuctionStatus";
import CardViewer from "../../../components/CardViewer";
import Accordion from "../../../components/Accordion";
import DetailCard from "../../../components/DetailCard";
import ConditionPill from "../../../components/ConditionPill";
import Button, { CalendarIcon } from "../../../components/Button";
import CardTitle from "../../../components/CardTitle";
import OfferCard from "../../../components/OfferCard";
import { DETALLE_PILLS, type DetalleVariant } from "../pills";

// Título del accordion VISITAS · dot verde + texto (CardTitle acepta nodos)
const VISITAS_TITLE = (
  <span style={{ display: "inline-flex", alignItems: "center", gap: 7 }}>
    <span style={{ width: 8, height: 8, borderRadius: "50%", background: "#2DBE64", flexShrink: 0 }} />
    VISITAS
  </span>
);

// Cada ConditionPill mide 136×46 fijo (hug del Figma), no se estira. Padding
// lateral 10px y texto 12px/14px para que las etiquetas largas (p.ej. «Cuota
// mínima de 2 participantes») entren en ese ancho. `.pcondpill.dt-pill` gana en
// especificidad al `.pcondpill` base.
const DETALLE_PILL_STYLES = `
.pcondpill.dt-pill { width: 136px; box-sizing: border-box; padding-left: 10px; padding-right: 10px; font-size: 12px; line-height: 14px; }
/* Pill solitaria en fila impar (3 pills) → centrada */
.pcondpill.dt-pill.dt-pill-c { grid-column: 1 / -1; justify-self: center; }
`;

const DETALLE_IMAGES = Array.from({ length: 8 }, function img() { return "/demo/bronco.jpg"; });

export interface DetalleProps {
  /** Variante de la oferta — controla AuctionStatus/CardViewer/DetailCard y los pills. */
  variant?: DetalleVariant;
  className?: string;
}

export const DETALLE_WIDTH = 799;
export const DETALLE_HEIGHT = 1483;

export default function Detalle({ variant = "live", className = "" }: DetalleProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="detalle"
      style={{
        position: "relative",
        width: DETALLE_WIDTH,
        height: DETALLE_HEIGHT,
        background: "#ffffff",
        overflow: "hidden",
      }}
    >
      {/* Fila de 2 columnas alineadas por arriba (top 16). El AuctionStatus (header
          del carro) va DENTRO de la columna izquierda, pegado al CardViewer, así su
          top coincide con el del DetailCard de la derecha (ambas columnas empiezan
          a la misma altura). */}
      <style suppressHydrationWarning dangerouslySetInnerHTML={{ __html: DETALLE_PILL_STYLES }} />
      <div
        style={{
          position: "absolute",
          top: 16,
          left: 16,
          right: 16,
          display: "flex",
          alignItems: "flex-start",
          justifyContent: "space-between",
        }}
      >
        {/* Columna izquierda */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16, width: 443 }}>
          {/* AuctionStatus pegado encima del CardViewer (sin gap) */}
          <div style={{ display: "flex", flexDirection: "column" }}>
            <AuctionStatus variant={variant} />
            <CardViewer images={DETALLE_IMAGES} variant={variant} />
          </div>
          <Accordion title="INFORMACIÓN GENERAL" />
          <Accordion title="CONDICIONES DE OFRECIMIENTO" />
        </div>

        {/* Columna derecha */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16, width: 311 }}>
          <DetailCard variant={variant} />

          {/* Card de fondo (311×132) con las ConditionPills (cambian según variante) */}
          <div
            style={{
              width: 311,
              boxSizing: "border-box",
              padding: 12,
              background: "#ffffff",
              borderRadius: 8,
              boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
              display: "grid",
              gridTemplateColumns: "136px 136px",
              justifyContent: "space-between",
              rowGap: 16,
            }}
          >
            {DETALLE_PILLS[variant].map(function renderPill(p, i, arr) {
              const lone = arr.length % 2 === 1 && i === arr.length - 1;
              return <ConditionPill key={i} className={`dt-pill${lone ? " dt-pill-c" : ""}`} variant={p.tone}>{p.label}</ConditionPill>;
            })}
          </div>

          {/* Subascoins Banner · placeholder 311 × 112 */}
          <div
            data-slot="subascoins-banner"
            style={{
              width: 311,
              height: 112,
              boxSizing: "border-box",
              borderRadius: 8,
              background: "#E9EAEC",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontFamily: "monospace",
              fontSize: 12,
              letterSpacing: "0.08em",
              color: "#9AA1AC",
            }}
          >
            SUBASCOINS BANNER
          </div>

          {/* Accordion VISITAS (abierto) · texto + Button «Agenda tu visita» (secondary-sm) */}
          <Accordion title={VISITAS_TITLE} defaultOpen>
            <p style={{ margin: 0, fontSize: 12, lineHeight: "16px", color: "#191C1C", textAlign: "left" }}>
              Las visitas son previa cita y se te proporcionará la ubicación exacta después de que agendes tu visita.
            </p>
            <div style={{ display: "flex", justifyContent: "center", marginTop: 16 }}>
              <Button variant="secondary-sm" icon={<CalendarIcon />}>Agenda tu visita</Button>
            </div>
          </Accordion>

          {/* OFERTAS RELACIONADAS · card 311×436 con CardTitle (200×32) + grid 2×2
              de OfferCards short (el grid ocupa 279×348). */}
          <div
            style={{
              width: 311,
              boxSizing: "border-box",
              background: "#ffffff",
              borderRadius: 8,
              boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
              padding: 16,
            }}
          >
            <CardTitle title="OFERTAS RELACIONADAS" subtitle="" titleSize={14} />
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "134px 134px",
                justifyContent: "space-between",
                rowGap: 8,
                marginTop: 24,
              }}
            >
              <OfferCard size="short" variant="live" name="Audi Q3" year={2026} price="US$ 14,999" imageSrc="/demo/bronco.jpg" elevated />
              <OfferCard size="short" variant="live" name="Audi Q3" year={2026} price="US$ 14,999" imageSrc="/demo/bronco.jpg" elevated />
              <OfferCard size="short" variant="negotiable" name="Audi Q3" year={2026} imageSrc="/demo/bronco.jpg" elevated />
              <OfferCard size="short" variant="negotiable" name="Audi Q3" year={2026} imageSrc="/demo/bronco.jpg" elevated />
            </div>
          </div>
        </div>
      </div>

      {/* Secondary Banner 766 × 100 · a 16px del bottom, centrado horizontalmente */}
      <div
        data-slot="secondary-banner"
        style={{
          position: "absolute",
          left: "50%",
          bottom: 16,
          transform: "translateX(-50%)",
          width: 766,
          height: 100,
          borderRadius: 8,
          background: "#E9EAEC",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontFamily: "monospace",
          fontSize: 12,
          letterSpacing: "0.08em",
          color: "#9AA1AC",
        }}
      >
        SECONDARY BANNER
      </div>
    </div>
  );
}

/**
 * DetalleMobile — Bloque de Concorde (Voyager DS)
 *
 * Página de detalle · mobile (420 de ancho). Estructura:
 *   · Header 420×64 (Button «Ingresa»)
 *   · AuctionStatus + CardViewer a TODO el ancho (carro + filmstrip)
 *   · Contenido a 16px de margen (388 de ancho):
 *       - DetailCard (388×390 — más ancho que en desktop, mismo alto)
 *       - ConditionPills (card 388×132)
 *       - Accordions (388×66 cada uno)
 */

"use client";

import type { JSX } from "react";
import AppHeader from "../../header/desktop/Header";
import AuctionStatus from "../../../components/AuctionStatus";
import CardViewer from "../../../components/CardViewer";
import DetailCard from "../../../components/DetailCard";
import ConditionPill from "../../../components/ConditionPill";
import Accordion from "../../../components/Accordion";
import CardTitle from "../../../components/CardTitle";
import OfferCard from "../../../components/OfferCard";
import Button, { CalendarIcon } from "../../../components/Button";
import { DETALLE_PILLS, type DetalleVariant } from "../pills";

export const DETALLE_MOBILE_WIDTH = 420;
export const DETALLE_MOBILE_HEIGHT = 2230;

const DETALLE_IMAGES = Array.from({ length: 8 }, function img() { return "/demo/bronco.jpg"; });

// Overrides puntuales: DetailCard a 388, pills que llenan su columna y las
// OfferCards short más grandes (170×210, imagen 152) para el grid de ofertas.
const MOBILE_STYLES = `
.dt-detail-m.pdetail { width: 388px; max-width: 388px; min-height: 390px; }
.pcondpill.dt-pill-m { width: 100%; box-sizing: border-box; padding-left: 12px; padding-right: 12px; font-size: 13px; line-height: 15px; }
.pcondpill.dt-pill-m.dt-pill-c { grid-column: 1 / -1; justify-self: center; width: 170px; }
.pcard--short.dt-card-lg { width: 170px; height: 210px; }
.pcard--short.dt-card-lg .pcard__img { height: 152px; }
`;

// Título del accordion VISITAS · dot verde + texto
const VISITAS_TITLE = (
  <span style={{ display: "inline-flex", alignItems: "center", gap: 7 }}>
    <span style={{ width: 8, height: 8, borderRadius: "50%", background: "#2DBE64", flexShrink: 0 }} />
    VISITAS
  </span>
);

export interface DetalleMobileProps {
  /** Variante de la oferta — controla AuctionStatus/CardViewer/DetailCard y los pills. */
  variant?: DetalleVariant;
  className?: string;
}

export default function DetalleMobile({ variant = "live", className = "" }: DetalleMobileProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="detalle-mobile"
      style={{
        position: "relative",
        width: DETALLE_MOBILE_WIDTH,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      <style suppressHydrationWarning dangerouslySetInnerHTML={{ __html: MOBILE_STYLES }} />

      {/* Header 420×64 con el logo de la marca a la izquierda */}
      <AppHeader
        width={DETALLE_MOBILE_WIDTH}
        logo={<img src="/logo-preview.png" alt="VMC Subastas" style={{ height: 26, width: "auto", display: "block" }} />}
      />

      {/* AuctionStatus + CardViewer · a todo el ancho (carro + filmstrip) */}
      <div style={{ display: "flex", flexDirection: "column", width: "100%" }}>
        <AuctionStatus variant={variant} />
        <CardViewer images={DETALLE_IMAGES} variant={variant} />
      </div>

      {/* Contenido a 16px de margen (388 de ancho) */}
      <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: 16 }}>
        {/* DetailCard 388×390 */}
        <DetailCard variant={variant} className="dt-detail-m" />

        {/* ConditionPills · card 388×132 (cambian según variante) */}
        <div
          style={{
            width: 388,
            boxSizing: "border-box",
            padding: "12px 16px",
            background: "#ffffff",
            borderRadius: 8,
            boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            columnGap: 16,
            rowGap: 16,
          }}
        >
          {DETALLE_PILLS[variant].map(function renderPill(p, i, arr) {
            const lone = arr.length % 2 === 1 && i === arr.length - 1;
            return <ConditionPill key={i} className={`dt-pill-m${lone ? " dt-pill-c" : ""}`} variant={p.tone}>{p.label}</ConditionPill>;
          })}
        </div>

        {/* Accordions 388×66 */}
        <Accordion title="INFORMACIÓN GENERAL" />
        <Accordion title="CONDICIONES DE OFRECIMIENTO" />
        <Accordion title={VISITAS_TITLE}>
          <p style={{ margin: 0, fontSize: 12, lineHeight: "16px", color: "#191C1C", textAlign: "left" }}>
            Las visitas son previa cita y se te proporcionará la ubicación exacta después de que agendes tu visita.
          </p>
          <div style={{ display: "flex", justifyContent: "center", marginTop: 16 }}>
            <Button variant="secondary-sm" icon={<CalendarIcon />}>Agenda tu visita</Button>
          </div>
        </Accordion>

        {/* OFERTAS RELACIONADAS · card 388×524 con CardTitle + grid 2×2 de
            OfferCards short grandes (170×210, grid 356×436). */}
        <div
          style={{
            width: 388,
            height: 524,
            boxSizing: "border-box",
            background: "#ffffff",
            borderRadius: 8,
            boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
            padding: 16,
          }}
        >
          <CardTitle title="OFERTAS RELACIONADAS" subtitle="" titleSize={14} />
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "170px 170px",
              gap: 16,
              justifyContent: "space-between",
              marginTop: 24,
            }}
          >
            <OfferCard size="short" className="dt-card-lg" variant="live" name="Audi Q3" year={2026} price="US$ 14,999" imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard size="short" className="dt-card-lg" variant="live" name="Audi Q3" year={2026} price="US$ 14,999" imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard size="short" className="dt-card-lg" variant="negotiable" name="Audi Q3" year={2026} imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard size="short" className="dt-card-lg" variant="negotiable" name="Audi Q3" year={2026} imageSrc="/demo/bronco.jpg" elevated />
          </div>
        </div>

        {/* Secondary Banner · placeholder 387×230 */}
        <div
          data-slot="secondary-banner"
          style={{
            width: 387,
            height: 230,
            boxSizing: "border-box",
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          SECONDARY BANNER
        </div>
      </div>
    </div>
  );
}

/**
 * Condition pills del bloque Detalle según la variante de la oferta.
 * Módulo PLANO (sin "use client") para que desktop y mobile lo compartan.
 *   · live       → 4 condiciones, todas incluidas (filled)
 *   · negotiable → 3 condiciones: «Con Fee de Habilitación» (filled) +
 *                  «Sin…» no incluidas (outline)
 */

export type DetalleVariant = "live" | "negotiable";
export type DetallePill = { label: string; tone?: "filled" | "outline" };

export const DETALLE_PILLS: Record<DetalleVariant, DetallePill[]> = {
  live: [
    { label: "Con Precio Reserva" },
    { label: "Con Opción a Visitas" },
    { label: "Con Comisión" },
    { label: "Cuota mínima de 2 participantes" },
  ],
  negotiable: [
    { label: "Con Fee de Habilitación" },
    { label: "Sin Opción a Visitas", tone: "outline" },
    { label: "Sin Comisión", tone: "outline" },
  ],
};

"use client";

/**
 * AuctionStatus — Generado por Concorde
 * Fuente: Figma VOYAGER · "AuctionStatus" (nodo 2007:16992 / 2007:18454)
 *
 * Barra de cabecera de subasta: botón volver (‹) + título + subtítulo,
 * sobre gradiente. 2 variantes:
 *   · live       → gradiente naranja (#FF9639 → #EF852E → #BE3D00)
 *   · negotiable → gradiente teal   (#00DAE0 → #008688)
 * Sheen blanco superior (rgba 0.1 → 0). 443×60.
 */

import type { JSX, MouseEventHandler } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type AuctionStatusVariant = "live" | "negotiable";

export interface AuctionStatusProps {
  /** Variante de color (default "live") */
  variant?: AuctionStatusVariant;
  /** Título (default "Volkswagen Gol 2015") */
  title?: string;
  /** Subtítulo (default "Vendedor: SubasCars") */
  subtitle?: string;
  /** Callback del botón volver */
  onBack?: MouseEventHandler<HTMLButtonElement>;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-auctionstatus-styles";

const AUCTIONSTATUS_STYLES = `
.pauction {
  position: relative;
  width: 443px;
  max-width: 100%;
  height: 60px;
  border-radius: 0;
  overflow: hidden;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0 16px 0 14px;
  box-sizing: border-box;
  box-shadow: rgba(0,0,0,0.1) 0px 0px 16px 4px;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.pauction--live { background: linear-gradient(156deg, #FF9639 0%, #EF852E 50%, #BE3D00 100%); }
.pauction--negotiable { background: linear-gradient(90deg, #00DAE0 0%, #008688 100%); }
.pauction::before {
  content: "";
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 18px;
  background: linear-gradient(180deg, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 100%);
  pointer-events: none;
}
.pauction__back {
  appearance: none;
  border: none;
  background: transparent;
  width: 32px;
  height: 32px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  border-radius: 50%;
  position: relative;
  z-index: 1;
  color: #ffffff;
  -webkit-backdrop-filter: blur(2px);
  backdrop-filter: blur(2px);
  transition: background 0.18s, color 0.18s, transform 0.12s;
}
/* hover: círculo relleno (tono claro), chevron blanco */
.pauction--live .pauction__back:hover { background: #F99845; }
.pauction--negotiable .pauction__back:hover { background: #2BC4C7; }
/* pressed: círculo tono base, chevron gris #99A1AF */
.pauction--live .pauction__back:active { background: #ED8936; }
.pauction--negotiable .pauction__back:active { background: #00A8AB; }
.pauction__back:active { color: #99A1AF; transform: scale(0.96); }
.pauction__back:focus-visible { outline: 2px solid rgba(255,255,255,0.9); outline-offset: 2px; }
.pauction__back svg path { stroke: currentColor; }
.pauction__back svg { filter: drop-shadow(0 1px 1.5px rgba(0,0,0,0.25)); }
.pauction__text { position: relative; z-index: 1; min-width: 0; }
.pauction__title {
  margin: 0;
  font-size: 16px;
  font-weight: 600;
  line-height: 1.2;
  color: #ffffff;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  text-shadow: 0 1px 1.5px rgba(0,0,0,0.25);
}
.pauction__subtitle {
  margin: 2px 0 0;
  font-size: 12px;
  font-weight: 400;
  line-height: 1.2;
  color: rgba(255,255,255,0.92);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  text-shadow: 0 1px 2px rgba(120,40,0,0.25);
}
@media (prefers-reduced-motion: reduce) {
  .pauction__back { transition: none; }
}
`;

let _stylesInjected = false;

// ─── Component ────────────────────────────────────────────────────────────────

export default function AuctionStatus({
  variant = "live",
  title = "Volkswagen Gol 2015",
  subtitle = "Vendedor: SubasCars",
  onBack,
  className = "",
}: AuctionStatusProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = AUCTIONSTATUS_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: AUCTIONSTATUS_STYLES }} />
      <div className={["pauction", `pauction--${variant}`, className].filter(Boolean).join(" ")}>
        <button type="button" className="pauction__back" onClick={onBack} aria-label="Volver">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" aria-hidden="true">
            <path d="M15 6L9 12L15 18" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </button>
        <div className="pauction__text">
          <h3 className="pauction__title">{title}</h3>
          <p className="pauction__subtitle">{subtitle}</p>
        </div>
      </div>
    </>
  );
}

"use client";

/**
 * CardViewer — Generado por Concorde
 * Fuente: Figma VOYAGER · "ImageViewer" (2007:16993) + "Filmstrip" (2007:16994 / 2007:18456)
 *
 * Visor de imagen 443×362 (controles glass: expandir · ‹ · › · contador) CON
 * su tira de miniaturas (Filmstrip 443×87, drag-to-scroll) debajo, como UNA sola
 * unidad. Click en una miniatura → cambia la imagen grande al instante.
 *
 * 2 variantes (por el borde de la miniatura seleccionada):
 *   · live       → white → #F4AC59 → #8460E5 → white
 *   · negotiable → white → #4DDCDC → #6445DF → white
 *
 * Estado interno (no controlado) por defecto; o controlado vía selectedIndex.
 */

import { useId, useRef, useState } from "react";
import type { JSX, ReactNode, MouseEventHandler, PointerEvent as ReactPointerEvent } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type CardViewerVariant = "live" | "negotiable";

export interface CardViewerProps {
  /** Variante del borde de selección (default "live") */
  variant?: CardViewerVariant;
  /** URLs de las imágenes (visor + miniaturas) */
  images?: string[];
  /** Alt de la imagen grande */
  imageAlt?: string;
  /** Índice seleccionado (controlado, 0-based) */
  selectedIndex?: number;
  /** Índice inicial (no controlado, default 0) */
  defaultIndex?: number;
  /** Callback al cambiar de imagen (click en miniatura o ‹/›) */
  onSelect?: (index: number) => void;
  /** Click en el botón expandir */
  onExpand?: MouseEventHandler<HTMLButtonElement>;
  /** Embebido dentro de una card padre: el visor va a ras (sin sombra ni
   *  redondeo propios), porque el borde/redondeo los pone el contenedor. */
  embedded?: boolean;
  /** Slot opcional ARRIBA del visor, DENTRO de la card. Cuando se pasa, un solo
   *  borde gradiente + redondeo inferior envuelve header+visor (el filmstrip
   *  queda fuera, debajo). Úsalo para el conjunto SalaStatus + visor. */
  header?: ReactNode;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-cardviewer-styles";

const CARDVIEWER_STYLES = `
.pcardv {
  display: flex;
  flex-direction: column;
  gap: 9px;
  width: 443px;
  max-width: 100%;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}

/* ── Visor de imagen ── */
.pcardv__viewer {
  position: relative;
  width: 100%;
  height: 362px;
  border-radius: 0 0 16px 16px;
  overflow: hidden;
  background: #F2F4F3;
  box-shadow: rgba(0,0,0,0.1) 0px 0px 16px 4px;
}
