        role={onClick ? "button" : undefined}
        tabIndex={onClick ? 0 : undefined}
        onKeyDown={function handleKey(e) {
          if (onClick && (e.key === "Enter" || e.key === " ")) onClick();
        }}
      >
        {/* Image */}
        <div className="pcard__img">
          {imageSrc && (
            <img src={imageSrc} alt={imageAlt ?? name} loading="lazy" />
          )}
          {badge && (
            <div className="pcard__img-badge">{badge}</div>
          )}
        </div>

        {/* Body */}
        <div className="pcard__body">
          <div className="pcard__meta">
            <h3 className="pcard__name">{name}</h3>
            <p className="pcard__year">{String(year)}</p>
          </div>

          {/* Price row â€” live / proxima / when price provided */}
          {showPriceRow && (
            <div className="pcard__price-row">
              <div className="pcard__price-left">
                <div className="pcard-pprice" aria-hidden="true">
                  <PriceGem w={30} h={32} />
                </div>
                <span className="pcard__price-text">{price}</span>
              </div>
              {LikeBtn}
            </div>
          )}

          {/* Like row â€” negotiable / expired (no price shown) */}
          {showLikeRow && (
            <div className="pcard__like-row">
              {LikeBtn}
            </div>
          )}
        </div>
      </article>
    </>
  );
}

/**
 * Dimensiones del bloque Header — módulo PLANO (sin "use client") para que los
 * Server Components (catálogo /blocks, páginas de bloque) puedan importar estas
 * constantes sin que se evalúen a undefined → NaN en los cálculos de escala.
 */

export const HEADER_WIDTH = 798;
export const HEADER_HEIGHT = 64;

/**
 * Header — Bloque de Concorde (Voyager DS)
 *
 * Barra superior 798 × 64 con fondo vault (#2E0F70). A la derecha lleva el
 * Button «Ingresa» (variante sm-guest, con UserIcon), a 16px del borde y
 * centrado verticalmente — igual que el export de Figma (1312:4674).
 *
 * Si se pasa `username`, el CTA cambia a la variante logueada: «Bienvenido,
 * {username}» (Button sm-logged-in) — usado p.ej. en la Zona de usuario.
 */

"use client";

import type { JSX, ReactNode } from "react";
import Button, { UserIcon } from "../../../components/Button";
import { HEADER_WIDTH, HEADER_HEIGHT } from "./dimensions";

export interface HeaderProps {
  /** Ancho de la barra. Por defecto HEADER_WIDTH (798, desktop); 420 en mobile. */
  width?: number | string;
  /** Logo a la izquierda (slot). En desktop no se usa (el logo va en el Sidebar);
   *  en mobile se pasa el logo de la marca. */
  logo?: ReactNode;
  /** Usuario logueado. Si se pasa, el CTA muestra «Bienvenido, {username}»
   *  (variante sm-logged-in) en vez de «Ingresa» (sm-guest). */
  username?: string;
  className?: string;
}

export default function Header({ width = HEADER_WIDTH, logo, username, className = "" }: HeaderProps): JSX.Element {
  return (
    <header
      className={className}
      data-block="header"
      style={{
        width,
        height: HEADER_HEIGHT,
        background: "#2E0F70",
        display: "flex",
        alignItems: "center",
        justifyContent: logo ? "space-between" : "flex-end",
        padding: "0 16px",
        flexShrink: 0,
        boxSizing: "border-box",
      }}
    >
      {logo}
      {username ? (
        <Button variant="sm-logged-in" username={username} icon={<UserIcon />} />
      ) : (
        <Button variant="sm-guest" icon={<UserIcon />}>
          Ingresa
        </Button>
      )}
    </header>
  );
}
